mapper.select:
SELECT scp.id, scp.user_id, scp.product_id, scp.quantity, scp.created_date, scp.modified_date, p.name AS product_name, p.product_category_id AS category_id, pc.name AS category_name, p.price, p.image_url, COALESCE(CAST(f.calories AS SIGNED), 0) AS calories, COALESCE(CAST(f.protein AS SIGNED), 0) AS protein, COALESCE(CAST(f.carbs AS SIGNED), 0) AS carbs, COALESCE(CAST(f.fat AS SIGNED), 0) AS fat FROM shopping_cart_products scp JOIN products p ON scp.product_id = p.id LEFT JOIN product_categories pc ON p.product_category_id = pc.id LEFT JOIN food f ON p.food_id = f.id WHERE scp.user_id = #{userId} AND scp.deleted_date IS NULL AND p.deleted_date IS NULL AND scp.id IN
#{cartItemId}
ORDER BY scp.created_date DESC

mapper.update:
UPDATE shopping_cart_products
SET quantity = LEAST(quantity + #{quantity}, 100),
    modified_date = CURRENT_TIMESTAMP
WHERE user_id = #{userId}
  AND product_id = #{productId}
  AND deleted_date IS NULL

UPDATE shopping_cart_products
SET quantity = LEAST(#{quantity}, 100),
    modified_date = CURRENT_TIMESTAMP
WHERE id = #{cartItemId}
  AND user_id = #{userId}
  AND deleted_date IS NULL

UPDATE shopping_cart_products
SET deleted_date = CURRENT_TIMESTAMP,
    modified_date = CURRENT_TIMESTAMP
WHERE id = #{cartItemId}
  AND user_id = #{userId}
  AND deleted_date IS NULL
